import React from 'react';
import { Card, Stack, Divider } from '@ggui-ai/design/primitives';
import { Heading, Text } from '@ggui-ai/design/primitives';

interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

export default function GeneratedComponent(props: Props) {
  const {
    city,
    temperature,
    condition,
    humidity,
    windSpeed,
    unit = 'C',
    forecast = [],
  } = props;

  return (
    <Card shadow="md" padding={24} radius="lg" border={true}>
      <Stack gap={24}>
        {/* Header Section */}
        <Stack direction="vertical" gap={8}>
          <Heading level={2}>{city}</Heading>
          <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
            {condition}
          </Text>
        </Stack>

        {/* Current Temperature */}
        <Text size="4xl" weight="bold">
          {temperature}°{unit}
        </Text>

        {/* Stats Row */}
        <Stack direction="horizontal" gap={16}>
          <Stack gap={4}>
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
              Humidity
            </Text>
            <Text variant="label">{humidity}%</Text>
          </Stack>
          <Stack gap={4}>
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
              Wind
            </Text>
            <Text variant="label">{windSpeed} km/h</Text>
          </Stack>
        </Stack>

        <Divider margin={0} />

        {/* 5-Day Forecast */}
        <Stack direction="horizontal" justify="between" gap={8}>
          {forecast.map((f, index) => (
            <Stack key={index} align="center" gap={8}>
              <Text variant="label">{f.day ?? 'Day'}</Text>
              <Text size="2xl">{f.icon ?? '☀️'}</Text>
              <Text variant="bodySmall">
                {f.high}°/{f.low}°
              </Text>
            </Stack>
          ))}
        </Stack>
      </Stack>
    </Card>
  );
}

import React, { useState, useMemo, useEffect } from 'react';
import {
  Container,
  Card,
  Stack,
  Box,
  Divider,
  Spacer,
  Text,
  Heading,
} from '@ggui-ai/design/primitives';
import {
  Input,
  TextArea,
  RadioGroup,
  Checkbox,
  Progress,
  FormField,
  Button,
} from '@ggui-ai/design/components';

interface Props {
  featureOptions: string[];
  satisfactionLabels: string[];
  onSubmit: (data: {
    name: string;
    email: string;
    satisfaction: number;
    features: string[];
    comments: string;
  }) => void;
}

export default function GeneratedComponent(props: Props) {
  const [currentStep, setCurrentStep] = useState(1);
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    satisfaction: 2,
    features: [] as string[],
    comments: '',
  });
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [errors, setErrors] = useState<{ name?: string; email?: string }>({});

  useEffect(() => {
    const handleData = (event: any) => {
      console.log('Agent data received:', event.detail);
    };
    window.addEventListener('ggui:agent-data', handleData);
    return () => window.removeEventListener('ggui:agent-data', handleData);
  }, []);

  const progress = useMemo(() => ((currentStep - 1) / 4) * 100, [currentStep]);

  const validateStep1 = () => {
    const newErrors: { name?: string; email?: string } = {};
    if (!formData.name.trim()) newErrors.name = 'Name is required';
    if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(formData.email))
      newErrors.email = 'Valid email is required';
    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleNext = () => {
    if (currentStep === 1 && !validateStep1()) return;
    if (currentStep < 5) setCurrentStep((s) => s + 1);
  };

  const handleBack = () => setCurrentStep((s) => Math.max(1, s - 1));

  const handleSubmit = () => {
    setIsSubmitting(true);
    props.onSubmit(formData);
  };

  const toggleFeature = (feature: string) => {
    setFormData((prev) => ({
      ...prev,
      features: prev.features.includes(feature)
        ? prev.features.filter((f) => f !== feature)
        : [...prev.features, feature],
    }));
  };

  return (
    <Container maxWidth="md" padding="24px">
      <Stack gap={24}>
        <Stack gap={8}>
          <Heading level={2}>Customer Survey</Heading>
          <Progress
            value={progress}
            variant="default"
            size="md"
            showLabel={true}
          />
          <Text variant="bodySmall">Step {currentStep} of 4</Text>
        </Stack>

        <Card shadow="md" padding={24} radius="lg">
          {currentStep === 1 && (
            <Stack gap={16}>
              <FormField label="Name" required error={errors.name}>
                <Input
                  label="Name"
                  value={formData.name}
                  onChange={(v) => setFormData({ ...formData, name: v })}
                />
              </FormField>
              <FormField label="Email" required error={errors.email}>
                <Input
                  label="Email"
                  type="email"
                  value={formData.email}
                  onChange={(v) => setFormData({ ...formData, email: v })}
                />
              </FormField>
            </Stack>
          )}

          {currentStep === 2 && (
            <RadioGroup
              label="How satisfied are you?"
              value={String(formData.satisfaction)}
              onChange={(v) =>
                setFormData({ ...formData, satisfaction: Number(v) })
              }
              options={props.satisfactionLabels.map((l, i) => ({
                label: l,
                value: String(i),
              }))}
            />
          )}

          {currentStep === 3 && (
            <Stack gap={12}>
              <Text variant="label">Feature Interests</Text>
              {props.featureOptions.map((opt) => (
                <Checkbox
                  key={opt}
                  label={opt}
                  checked={formData.features.includes(opt)}
                  onChange={() => toggleFeature(opt)}
                />
              ))}
            </Stack>
          )}

          {currentStep === 4 && (
            <FormField label="Comments">
              <TextArea
                label="Comments"
                value={formData.comments}
                onChange={(v) => setFormData({ ...formData, comments: v })}
                maxLength={500}
                showCount
              />
            </FormField>
          )}

          {currentStep === 5 && (
            <Stack gap={16}>
              <Heading level={4}>Review</Heading>
              <Box
                background="var(--ggui-color-surfaceVariant)"
                padding={16}
                borderRadius={8}
              >
                <Stack gap={8}>
                  <Text><strong>Name:</strong> {formData.name}</Text>
                  <Text><strong>Email:</strong> {formData.email}</Text>
                  <Text><strong>Satisfaction:</strong> {props.satisfactionLabels[formData.satisfaction]}</Text>
                  <Text><strong>Features:</strong> {formData.features.join(', ') || 'None selected'}</Text>
                  <Text><strong>Comments:</strong> {formData.comments || 'N/A'}</Text>
                </Stack>
              </Box>
            </Stack>
          )}
        </Card>

        <Stack direction="horizontal" gap={16} justify="end">
          {currentStep > 1 && (
            <Button variant="ghost" onClick={handleBack}>Back</Button>
          )}
          {currentStep < 5 ? (
            <Button
              variant="primary"
              onClick={handleNext}
              disabled={currentStep === 1 && (!formData.name || !formData.email)}
            >
              Next
            </Button>
          ) : (
            <Button
              variant="primary"
              loading={isSubmitting}
              onClick={handleSubmit}
            >
              Submit
            </Button>
          )}
        </Stack>
      </Stack>
    </Container>
  );
}

import React, { useState, useEffect } from 'react';
import { 
  Container, 
  Stack, 
  Card, 
  Text, 
  Heading, 
  Button, 
  Input, 
  Select, 
  Badge, 
  Avatar,
  Box
} from '@ggui-ai/design/primitives';

interface Props {
  tasks: Array<{ 
    id?: string; 
    title?: string; 
    priority?: 'low' | 'medium' | 'high'; 
    assignee?: string; 
    column?: string; 
    dueDate?: string 
  }>;
  columns: Array<{ id?: string; name?: string }>;
  onTaskUpdate?: (payload: { action: 'move' | 'edit' | 'create', taskId: string, data: any }) => void;
}

export default function GeneratedComponent(props: Props) {
  const [tasks, setTasks] = useState(props.tasks || []);
  const [isAdding, setIsAdding] = useState<string | null>(null);
  const [newTaskTitle, setNewTaskTitle] = useState("");
  const [newTaskPriority, setNewTaskPriority] = useState<'low' | 'medium' | 'high'>('medium');
  const [editingId, setEditingId] = useState<string | null>(null);
  const [editTitle, setEditTitle] = useState("");

  useEffect(() => {
    const handleData = (event: any) => {
      if (event.detail) setTasks(event.detail);
    };
    window.addEventListener('ggui:agent-data', handleData);
    return () => window.removeEventListener('ggui:agent-data', handleData);
  }, []);

  const handleUpdate = (action: 'move' | 'edit' | 'create', taskId: string, data: any) => {
    if (action === 'create') {
      const newTask = { ...data, id: Date.now().toString() };
      setTasks([...tasks, newTask]);
    } else {
      setTasks(tasks.map(t => (t.id === taskId ? { ...t, ...data } : t)));
    }
    props.onTaskUpdate?.({ action, taskId, data });
  };

  const doneColumnId = props.columns.find(c => c.name?.toLowerCase() === 'done')?.id;
  const completedCount = tasks.filter(t => t.column === doneColumnId).length;

  return (
    <Container maxWidth="full" padding="var(--ggui-spacing-6)">
      <Stack direction="horizontal" gap="var(--ggui-spacing-4)" style={{ marginBottom: 'var(--ggui-spacing-6)' }} align="center">
        <Heading level={2}>Kanban Board</Heading>
        <Badge variant="secondary">Total: {tasks.length}</Badge>
        <Badge variant="success">Completed: {completedCount}</Badge>
      </Stack>

      <Stack direction="horizontal" gap="var(--ggui-spacing-6)" align="start" wrap={true}>
        {props.columns.map(col => (
          <Box 
            key={col.id}
            padding={16}
            background="var(--ggui-color-surfaceVariant)"
            borderRadius="var(--ggui-shape-radius-lg)"
            style={{ minWidth: 280 }}
          >
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={4}>{col.name} ({tasks.filter(t => t.column === col.id).length})</Heading>

              <Stack gap="var(--ggui-spacing-2)">
                {tasks.filter(t => t.column === col.id).map(task => (
                  <Card key={task.id} padding={12} shadow="sm" radius="lg" border={true}>
                    <Stack gap="var(--ggui-spacing-2)">
                      {editingId === task.id ? (
                        <Stack gap="var(--ggui-spacing-1)">
                          <Input label="Edit Title" value={editTitle} onChange={setEditTitle} />
                          <Button size="xs" onClick={() => { handleUpdate('edit', task.id!, { title: editTitle }); setEditingId(null); }}>Save</Button>
                        </Stack>
                      ) : (
                        <div role="button" onDoubleClick={() => { setEditingId(task.id ?? null); setEditTitle(task.title ?? ""); }}>
                          <Text>{task.title ?? "Untitled Task"}</Text>
                        </div>
                      )}

                      <Stack direction="horizontal" gap="var(--ggui-spacing-2)" align="center">
                        <Badge variant={task.priority === 'high' ? 'error' : task.priority === 'medium' ? 'info' : 'secondary'}>
                          {task.priority ?? 'medium'}
                        </Badge>
                        {task.assignee && <Avatar name={task.assignee} size={24} shape="circle" />}
                      </Stack>

                      {task.dueDate && <Text variant="caption">Due: {task.dueDate}</Text>}

                      <Select 
                        label="Move task" 
                        value={task.column ?? ""} 
                        onChange={(val) => handleUpdate('move', task.id!, { column: val })}
                        options={props.columns.map(c => ({ value: c.id ?? "", label: c.name ?? "" }))}
                      />
                    </Stack>
                  </Card>
                ))}
              </Stack>

              {isAdding === col.id ? (
                <Stack gap="var(--ggui-spacing-2)">
                  <Input label="Task Title" value={newTaskTitle} onChange={setNewTaskTitle} />
                  <Select 
                    label="Priority" 
                    value={newTaskPriority} 
                    onChange={(v) => setNewTaskPriority(v as any)} 
                    options={[{value:'low', label:'Low'}, {value:'medium', label:'Medium'}, {value:'high', label:'High'}]} 
                  />
                  <Button onClick={() => { 
                    handleUpdate('create', '', { title: newTaskTitle, priority: newTaskPriority, column: col.id }); 
                    setIsAdding(null); 
                    setNewTaskTitle(""); 
                  }}>Add Task</Button>
                  <Button variant="ghost" size="xs" onClick={() => setIsAdding(null)}>Cancel</Button>
                </Stack>
              ) : (
                <Button variant="ghost" onClick={() => setIsAdding(col.id ?? null)} aria-label={`Add task to ${col.name}`}>+ Add Task</Button>
              )}
            </Stack>
          </Box>
        ))}
      </Stack>
    </Container>
  );
}

import React, { useState, useMemo } from 'react';
import { Container, Stack, Card, Box, Text, Heading, Input, Spacer } from '@ggui-ai/design/primitives';

interface Props {
  elements: Array<{
    atomicNumber?: number;
    symbol?: string;
    name?: string;
    atomicWeight?: number;
    category?: string;
    row?: number;
    col?: number;
  }>;
}

const CATEGORY_COLORS: Record<string, string> = {
  'noble-gas': 'var(--ggui-color-info-100)',
  'halogen': 'var(--ggui-color-warning-100)',
  'alkali-metal': 'var(--ggui-color-primary-100)',
  'alkaline-earth-metal': 'var(--ggui-color-success-100)',
  'transition-metal': 'var(--ggui-color-surfaceVariant)',
  'post-transition-metal': 'var(--ggui-color-container)',
  'nonmetal': 'var(--ggui-color-neutral-200)',
  'metalloid': 'var(--ggui-color-neutral-300)',
  'lanthanoid': 'var(--ggui-color-primary-50)',
  'actinoid': 'var(--ggui-color-primary-50)',
};

export default function GeneratedComponent(props: Props) {
  const [selected, setSelected] = useState<Props['elements'][0] | null>(null);
  const [query, setQuery] = useState('');

  const filtered = useMemo(() => {
    const q = query.toLowerCase();
    return props.elements.map((el) => ({
      ...el,
      isMatch: !q || (el.name?.toLowerCase().includes(q) || el.symbol?.toLowerCase().includes(q)),
    }));
  }, [props.elements, query]);

  const categories = useMemo(() => Array.from(new Set(props.elements.map((e) => e.category))), [props.elements]);

  return (
    <Container maxWidth="full" padding={24}>
      <Stack gap={24}>
        <Stack gap={16} align="center">
          <Heading level={1}>Periodic Table</Heading>
          <Box style={{ width: '100%', maxWidth: '400px' }}>
            <Input label="Search Elements" placeholder="Search by name or symbol..." value={query} onChange={setQuery} />
          </Box>
        </Stack>

        <Box style={{ overflowX: 'auto', paddingBottom: 'var(--ggui-spacing-4)' }}>
          <div style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(18, minmax(60px, 1fr))',
            gap: 'var(--ggui-spacing-1)',
            minWidth: '1000px'
          }}>
            {filtered.map((el) => (
              <div
                key={el.atomicNumber}
                role="button"
                aria-label={`Element ${el.name}, atomic number ${el.atomicNumber}`}
                style={{
                  gridColumn: el.col,
                  gridRow: el.row,
                  cursor: 'pointer',
                  outline: 'none',
                }}
                onClick={() => setSelected(el)}
                onKeyDown={(e) => (e.key === 'Enter' || e.key === ' ') && setSelected(el)}
                tabIndex={0}
              >
                <Card
                  radius="sm"
                  padding={8}
                  style={{
                    height: '100%',
                    backgroundColor: el.isMatch ? (CATEGORY_COLORS[el.category ?? ''] ?? 'var(--ggui-color-surface)') : 'var(--ggui-color-surface)',
                    opacity: el.isMatch ? 1 : 0.3,
                    transition: 'transform 200ms ease, box-shadow 200ms ease',
                    position: 'relative'
                  }}
                >
                  <Text variant="caption" style={{ position: 'absolute', top: 4, left: 4 }}>{el.atomicNumber}</Text>
                  <Stack align="center" justify="center" style={{ height: '100%' }}>
                    <Text weight="bold" size="lg">{el.symbol}</Text>
                  </Stack>
                </Card>
              </div>
            ))}
          </div>
        </Box>

        <Stack direction="horizontal" gap={12} wrap justify="center">
          {categories.filter(Boolean).map((cat) => (
            <Stack key={cat} direction="horizontal" gap={8} align="center">
              <Box style={{ width: 16, height: 16, backgroundColor: CATEGORY_COLORS[cat ?? ''] ?? 'var(--ggui-color-outline)' }} borderRadius={4} />
              <Text variant="caption">{cat}</Text>
            </Stack>
          ))}
        </Stack>

        {selected && (
          <Card shadow="md" padding={24}>
            <Stack gap={8}>
              <Heading level={3}>{selected.name}</Heading>
              <Text variant="body">Symbol: {selected.symbol}</Text>
              <Text variant="body">Atomic Number: {selected.atomicNumber}</Text>
              <Text variant="body">Atomic Weight: {selected.atomicWeight}</Text>
              <Text variant="body">Category: {selected.category}</Text>
            </Stack>
          </Card>
        )}
      </Stack>
    </Container>
  );
}

import React, { useState, useEffect, useRef } from 'react';
import { Box, Stack, Text, Heading, Input, Button, Divider, Badge } from '@ggui-ai/design/primitives';

interface Props {
  /** Chat window title */
  title: string;
  /** Current user name (for right-aligning own messages) */
  currentUser: string;
  /** Number of participants */
  participantCount?: number;
  /** Array of messages with sender name, text, and ISO timestamp */
  messages: Array<{ sender?: string; text?: string; timestamp?: string }>;
  /** Callback for sending a message */
  onSendMessage: (payload: { text: string; timestamp: string }) => void;
}

export default function GeneratedComponent(props: Props) {
  const [messages, setMessages] = useState(props.messages);
  const [inputValue, setInputValue] = useState('');
  const listRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const handleIncomingMessage = (event: any) => {
      const newMessage = event.detail;
      if (newMessage) {
        setMessages((prev) => [...prev, newMessage]);
      }
    };

    window.addEventListener('ggui:agent-data', handleIncomingMessage);
    return () => window.removeEventListener('ggui:agent-data', handleIncomingMessage);
  }, []);

  useEffect(() => {
    if (listRef.current) {
      listRef.current.scrollTop = listRef.current.scrollHeight;
    }
  }, [messages]);

  const handleSubmit = () => {
    const trimmed = inputValue.trim();
    if (!trimmed) return;

    const payload = {
      text: trimmed,
      timestamp: new Date().toISOString(),
    };

    props.onSendMessage(payload);
    setMessages((prev) => [...prev, { sender: props.currentUser, ...payload }]);
    setInputValue('');
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSubmit();
    }
  };

  return (
    <Box
      borderRadius="var(--ggui-shape-radius-lg, 12px)"
      background="var(--ggui-color-surface, #ffffff)"
      style={{
        height: '500px',
        display: 'flex',
        flexDirection: 'column',
        border: '1px solid var(--ggui-color-outline, #d4d4d8)',
        overflow: 'hidden',
      }}
    >
      <Stack
        direction="horizontal"
        justify="between"
        align="center"
        style={{
          padding: 'var(--ggui-spacing-4, 16px)',
          borderBottom: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)',
        }}
      >
        <Heading level={3}>{props.title}</Heading>
        {props.participantCount !== undefined && (
          <Badge variant="secondary">{props.participantCount} participants</Badge>
        )}
      </Stack>

      <Box
        style={{
          flex: 1,
          overflowY: 'auto',
          padding: 'var(--ggui-spacing-4, 16px)',
        }}
        ref={listRef}
      >
        <div style={{ display: 'flex', flexDirection: 'column', gap: 'var(--ggui-spacing-4, 16px)' }}>
          {messages.map((msg, i) => {
            const isOwn = msg.sender === props.currentUser;
            const time = msg.timestamp ? new Date(msg.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }) : '';

            return (
              <Stack key={i} align={isOwn ? 'end' : 'start'}>
                <Box
                  paddingX="var(--ggui-spacing-3, 12px)"
                  paddingY="var(--ggui-spacing-2, 8px)"
                  borderRadius="var(--ggui-shape-radius-md, 8px)"
                  background={isOwn ? 'var(--ggui-color-primary-600, #0284c7)' : 'var(--ggui-color-surfaceVariant, #f4f4f5)'}
                  style={{ maxWidth: '80%' }}
                >
                  <Text color={isOwn ? 'white' : 'var(--ggui-color-onSurface, #18181b)'}>
                    {msg.text}
                  </Text>
                  <Text
                    variant="caption"
                    color={isOwn ? 'var(--ggui-color-primary-100, #e0f2fe)' : 'var(--ggui-color-onSurfaceVariant, #52525b)'}
                    style={{ marginTop: 'var(--ggui-spacing-1, 4px)', textAlign: isOwn ? 'right' : 'left' }}
                  >
                    {time}
                  </Text>
                </Box>
              </Stack>
            );
          })}
        </div>
      </Box>

      <Divider />

      <Stack direction="horizontal" gap="var(--ggui-spacing-2, 8px)" style={{ padding: 'var(--ggui-spacing-4, 16px)' }}>
        <Input
          label="Message input"
          value={inputValue}
          onChange={(val) => setInputValue(val)}
          placeholder="Type a message..."
          style={{ flex: 1 }}
          onKeyDown={handleKeyDown}
        />
        <Button onClick={handleSubmit} disabled={!inputValue.trim()}>
          Send
        </Button>
      </Stack>
    </Box>
  );
}

import React, { useState, useEffect } from 'react';
import {
  Container,
  Card,
  Stack,
  Box,
  Heading,
  Text,
  Icon,
} from '@ggui-ai/design/primitives';

interface Props {
  /** Array of stocks with symbol, name, price, change, changePercent */
  stocks: Array<{
    symbol?: string;
    name?: string;
    price?: number;
    change?: number;
    changePercent?: number;
  }>;
  /** ISO timestamp of last price update */
  lastUpdated?: string;
}

export default function GeneratedComponent(props: Props) {
  const [stocks, setStocks] = useState(props.stocks);
  const [lastUpdated, setLastUpdated] = useState(props.lastUpdated);
  const [isConnecting, setIsConnecting] = useState(false);

  useEffect(() => {
    const handleData = (event: any) => {
      const data = event.detail;
      if (data && Array.isArray(data.stocks)) {
        setStocks(data.stocks);
        setLastUpdated(new Date().toISOString());
        setIsConnecting(false);
      }
    };

    window.addEventListener('ggui:agent-data', handleData);
    return () => window.removeEventListener('ggui:agent-data', handleData);
  }, []);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6, 24px)">
      <main role="main">
        <Stack gap="var(--ggui-spacing-6, 24px)">
          <Box
            paddingX="var(--ggui-spacing-4, 16px)"
            paddingY="var(--ggui-spacing-4, 16px)"
            borderRadius="var(--ggui-shape-radius-md, 8px)"
            background="var(--ggui-color-surfaceVariant, #f4f4f5)"
          >
            <Stack direction="horizontal" justify="between" align="center">
              <Heading level={2}>Market Watch</Heading>
              {lastUpdated && (
                <Text
                  variant="caption"
                  color="var(--ggui-color-onSurfaceVariant, #52525b)"
                >
                  Last Updated: {new Date(lastUpdated).toLocaleTimeString()}
                </Text>
              )}
            </Stack>
          </Box>

          <div
            style={{
              display: 'grid',
              gridTemplateColumns: 'repeat(auto-fit, minmax(300px, 1fr))',
              gap: 'var(--ggui-spacing-4, 16px)',
            }}
          >
            {stocks.map((stock, idx) => {
              const price = stock.price ?? 0;
              const change = stock.change ?? 0;
              const changePercent = stock.changePercent ?? 0;
              const isPositive = change >= 0;
              const color = isPositive
                ? 'var(--ggui-color-success-700, #15803d)'
                : 'var(--ggui-color-error-700, #b91c1c)';

              return (
                <Card
                  key={`${stock.symbol ?? 'unknown'}-${idx}`}
                  padding="var(--ggui-spacing-5, 20px)"
                >
                  <div role="listitem">
                    <Stack gap="var(--ggui-spacing-2, 8px)">
                      <Stack
                        direction="horizontal"
                        justify="between"
                        align="center"
                      >
                        <Heading
                          level={3}
                          aria-label={`Symbol ${stock.symbol ?? 'Unknown'}`}
                        >
                          {stock.symbol ?? 'N/A'}
                        </Heading>
                        <Text variant="bodyLarge" weight="medium">
                          ${price.toFixed(2)}
                        </Text>
                      </Stack>

                      <Text
                        variant="bodySmall"
                        color="var(--ggui-color-onSurfaceVariant, #52525b)"
                      >
                        {stock.name ?? 'Unknown Company'}
                      </Text>

                      <Box>
                        <Stack
                          direction="horizontal"
                          gap="var(--ggui-spacing-1, 4px)"
                          align="center"
                        >
                          <Icon
                            name={isPositive ? 'chevron-up' : 'chevron-down'}
                            size={16}
                            color={color}
                          />
                          <Text variant="label" color={color}>
                            {Math.abs(change).toFixed(2)} (
                            {Math.abs(changePercent).toFixed(2)}%)
                          </Text>
                        </Stack>
                      </Box>
                    </Stack>
                  </div>
                </Card>
              );
            })}
          </div>
        </Stack>
      </main>
    </Container>
  );
}

import React, { useState, useEffect } from 'react';
import {
  Container,
  Card,
  Stack,
  Heading,
  Button,
  Progress,
  Text,
  Divider,
  Input,
  Select,
  Toggle,
  RadioGroup,
  Box,
} from '@ggui-ai/design/primitives';

interface Props {
  initialProfile?: {
    name?: string;
    email?: string;
    avatar?: string;
    role?: string;
    emailNotifications?: boolean;
    theme?: string;
  };
  avatarOptions: string[];
  roleOptions: string[];
  onComplete?: (data: any) => void;
}

export default function GeneratedComponent(props: Props) {
  const { initialProfile = {}, avatarOptions, roleOptions, onComplete } = props;
  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState({
    name: initialProfile.name ?? '',
    email: initialProfile.email ?? '',
    avatar: initialProfile.avatar ?? (avatarOptions[0] ?? ''),
    role: initialProfile.role ?? (roleOptions[0] ?? ''),
    emailNotifications: initialProfile.emailNotifications ?? false,
    theme: initialProfile.theme ?? 'light',
  });
  const [errors, setErrors] = useState<Record<string, string>>({});

  useEffect(() => {
    const handleAgentData = (e: any) => {
      const detail = (e as CustomEvent).detail;
      if (detail) setFormData((prev) => ({ ...prev, ...detail }));
    };
    window.addEventListener('ggui:agent-data', handleAgentData as EventListener);
    return () => window.removeEventListener('ggui:agent-data', handleAgentData as EventListener);
  }, []);

  const validateStep1 = () => {
    const newErrors: Record<string, string> = {};
    if (!formData.name.trim()) newErrors.name = 'Name is required';
    if (!/^\S+@\S+\.\S+$/.test(formData.email)) newErrors.email = 'Invalid email format';
    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const updateField = (key: string, value: any) => {
    setFormData((prev) => ({ ...prev, [key]: value }));
    if (errors[key]) setErrors((prev) => ({ ...prev, [key]: '' }));
  };

  return (
    <Container maxWidth="md" padding="var(--ggui-spacing-6, 24px)">
      <Card shadow="md" padding="var(--ggui-spacing-6, 24px)" border={true}>
        <Stack gap={16}>
          <Stack gap={8}>
            <Heading level={5}>Step {step} of 3</Heading>
            <Progress value={(step / 3) * 100} variant="default" size="md" />
          </Stack>

          <Box paddingY="var(--ggui-spacing-4, 16px)">
            {step === 1 && (
              <Stack gap={16}>
                <Input
                  label="Name"
                  value={formData.name}
                  onChange={(v) => updateField('name', v)}
                  required
                  error={errors.name}
                />
                <Input
                  label="Email"
                  type="email"
                  value={formData.email}
                  onChange={(v) => updateField('email', v)}
                  required
                  error={errors.email}
                />
                <RadioGroup
                  label="Select Avatar"
                  value={formData.avatar}
                  onChange={(v) => updateField('avatar', v)}
                  options={avatarOptions.map((a) => ({ value: a, label: a }))}
                  direction="horizontal"
                />
              </Stack>
            )}

            {step === 2 && (
              <Stack gap={16}>
                <Select
                  label="Role"
                  value={formData.role}
                  onChange={(v) => updateField('role', v)}
                  options={roleOptions.map((r) => ({ value: r, label: r }))}
                />
                <Toggle
                  label="Email Notifications"
                  checked={formData.emailNotifications}
                  onChange={(v) => updateField('emailNotifications', v)}
                />
                <RadioGroup
                  label="Theme"
                  value={formData.theme}
                  onChange={(v) => updateField('theme', v)}
                  options={[
                    { value: 'light', label: 'Light' },
                    { value: 'dark', label: 'Dark' },
                  ]}
                  direction="horizontal"
                />
              </Stack>
            )}

            {step === 3 && (
              <Stack gap={12}>
                <Heading level={4}>Review Your Profile</Heading>
                {Object.entries(formData).map(([k, v]) => (
                  <Stack key={k} direction="horizontal" gap={8}>
                    <Text variant="label" style={{ textTransform: 'capitalize' }}>
                      {k.replace(/([A-Z])/g, ' $1')}:
                    </Text>
                    <Text>{String(v)}</Text>
                  </Stack>
                ))}
              </Stack>
            )}
          </Box>

          <Divider margin="var(--ggui-spacing-4, 16px) 0" />

          <Stack direction="horizontal" justify="between">
            <Button variant="ghost" disabled={step === 1} onClick={() => setStep((s) => s - 1)}>
              Go Back
            </Button>
            {step < 3 ? (
              <Button
                onClick={() => {
                  if (step === 1 ? validateStep1() : true) setStep((s) => s + 1);
                }}
              >
                Next
              </Button>
            ) : (
              <Button variant="primary" onClick={() => onComplete?.(formData)}>
                Complete Setup
              </Button>
            )}
          </Stack>
        </Stack>
      </Card>
    </Container>
  );
}
